import { writeFile } from "node:fs/promises";
import { resolve } from "node:path";

/**
 * Generate NOTICE.md from the pipeline config.
 *
 * @param {object} config - validated pipeline config
 * @param {string} transitDir - root of the data/transit/ directory
 * @returns {Promise<void>}
 */
export async function generateNotice(config, transitDir) {
    const lines = [];

    lines.push("# Transit Data Notice");
    lines.push("");
    lines.push(
        "This directory contains processed public transportation data generated by",
    );
    lines.push(
        "the transit station pipeline (`data/transit/`). See `sources.md` for",
    );
    lines.push("provenance details.");
    lines.push("");

    for (const locale of config.locales) {
        // OSM attribution.
        if (locale.osm) {
            lines.push("## OpenStreetMap");
            lines.push("");
            lines.push(
                `Locale "${locale.id}" includes data from OpenStreetMap, licensed under`,
            );
            lines.push(
                "the Open Database License (ODbL) 1.0. © OpenStreetMap contributors.",
            );
            lines.push("");
            lines.push(
                "Geofabrik extracts sourced from https://download.geofabrik.de/.",
            );
            lines.push("");
        }

        // GTFS feed attribution.
        if (locale.gtfs && locale.gtfs.length > 0) {
            lines.push("## GTFS Feeds");
            lines.push("");

            for (const feed of locale.gtfs) {
                lines.push(`### ${feed.label}`);
                lines.push("");

                if (feed.namespace === "odpt-tokyo-metro") {
                    lines.push(
                        "Tokyo Metro GTFS data is provided by Tokyo Metro Co., Ltd. via the",
                    );
                    lines.push(
                        "Public Transportation Open Data Center (ODPT) authenticated API.",
                    );
                    lines.push("");
                    lines.push(
                        "When using, displaying, or redistributing data derived from this feed,",
                    );
                    lines.push("include attribution to:");
                    lines.push("");
                    lines.push(
                        "- Public Transportation Open Data Center / Association for Open Data of Public Transportation",
                    );
                    lines.push("- Tokyo Metro Co., Ltd.");
                    lines.push("");
                } else if (feed.namespace === "odpt-toei-subway") {
                    lines.push(
                        "Toei Subway GTFS data is provided by the Tokyo Metropolitan Bureau of",
                    );
                    lines.push("Transportation via the ODPT public file API.");
                    lines.push("");
                    lines.push(
                        "When using, displaying, or redistributing data derived from this feed,",
                    );
                    lines.push("include attribution to:");
                    lines.push("");
                    lines.push(
                        "- Public Transportation Open Data Center / Association for Open Data of Public Transportation",
                    );
                    lines.push("- Tokyo Metropolitan Bureau of Transportation");
                    lines.push("");
                } else {
                    lines.push(`License: ${feed.license}`);
                    lines.push("");
                }
            }

            // ODPT boilerplate for ODPT-sourced feeds.
            const hasOdpt = locale.gtfs.some((f) =>
                f.namespace?.startsWith("odpt-"),
            );
            if (hasOdpt) {
                lines.push("### ODPT Terms");
                lines.push("");
                lines.push(
                    "ODPT-published datasets may be provided under license families including",
                );
                lines.push(
                    "CC0, CC BY 4.0, ODC BY 1.0, ODbL 1.0, the Public Transportation Open Data",
                );
                lines.push(
                    "Basic License, or challenge-specific licenses. Follow the license attached",
                );
                lines.push(
                    "to each source dataset, including credit/attribution requirements.",
                );
                lines.push("");
                lines.push(
                    "Before refreshing or redistributing generated data, review the current",
                );
                lines.push("ODPT terms, license, and developer guidelines:");
                lines.push("");
                lines.push(
                    "- Terms and guidelines: https://developer.odpt.org/terms",
                );
                lines.push(
                    "- Published datasets: https://ckan.odpt.org/dataset",
                );
                lines.push(
                    "- API specifications: https://developer.odpt.org/documents",
                );
                lines.push("");
                lines.push(
                    "No endorsement by ODPT, Tokyo Metro, or the Tokyo Metropolitan Bureau of",
                );
                lines.push("Transportation is implied.");
                lines.push("");
            }
        }
    }

    // Suggested attribution text (copy from existing ODPT NOTICE).
    lines.push("## Suggested Attribution Text");
    lines.push("");
    lines.push(
        "> Contains public transportation data made available by the Public",
    );
    lines.push(
        "> Transportation Open Data Center / Association for Open Data of Public",
    );
    lines.push(
        "> Transportation, including data provided by Tokyo Metro Co., Ltd. and the",
    );
    lines.push(
        "> Tokyo Metropolitan Bureau of Transportation. The data has been processed",
    );
    lines.push("> for use in Jet Lag Hide and Seek.");
    lines.push("");
    lines.push("Japanese:");
    lines.push("");
    lines.push(
        "> 本アプリケーションには、公共交通オープンデータセンター／公共交通オープンデータ協議会が公開するデータ（東京地下鉄株式会社および東京都交通局提供データを含む）を加工したデータが含まれます。",
    );
    lines.push("");

    await writeFile(resolve(transitDir, "NOTICE.md"), lines.join("\n"));
}
